-- Row Level Security (enable when using auth)
ALTER TABLE signals ENABLE ROW LEVEL SECURITY;
ALTER TABLE trades ENABLE ROW LEVEL SECURITY;
ALTER TABLE balances ENABLE ROW LEVEL SECURITY;
ALTER TABLE logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE performance_metrics ENABLE ROW LEVEL SECURITY;
ALTER TABLE pair_stats ENABLE ROW LEVEL SECURITY;
ALTER TABLE trade_lessons ENABLE ROW LEVEL SECURITY;

-- Service role bypass policies (adjust for your auth setup)
CREATE POLICY "Service full access signals" ON signals FOR ALL USING (true);
CREATE POLICY "Service full access trades" ON trades FOR ALL USING (true);
CREATE POLICY "Service full access balances" ON balances FOR ALL USING (true);
CREATE POLICY "Service full access logs" ON logs FOR ALL USING (true);
CREATE POLICY "Service full access metrics" ON performance_metrics FOR ALL USING (true);
CREATE POLICY "Service full access pair_stats" ON pair_stats FOR ALL USING (true);
CREATE POLICY "Service full access trade_lessons" ON trade_lessons FOR ALL USING (true);
